class WebSocketClient{constructor(t=""){this.basePath=t,this.ws=null,this.reconnectAttempts=0,this.maxReconnectAttempts=10,this.reconnectDelay=1e3,this.listeners=new Map,this.isConnected=!1,this.shouldReconnect=!0}connect(){if(this.ws&&(this.ws.readyState===WebSocket.OPEN||this.ws.readyState===WebSocket.CONNECTING))return;this.shouldReconnect=!0;const t=window.location.protocol==="https:"?"wss:":"ws:";let s=this.basePath||"";s&&!s.endsWith("/")&&(s+="/");const o=`${t}//${window.location.host}${s}ws`;console.log("WebSocket connecting to:",o,"basePath:",this.basePath);try{this.ws=new WebSocket(o),this.ws.onopen=()=>{console.log("WebSocket connected"),this.isConnected=!0,this.reconnectAttempts=0,this.emit("connected")},this.ws.onmessage=e=>{try{if(e.data&&e.data.length>10485760){console.error("WebSocket message too large:",e.data.length,"bytes"),this.ws.close();return}const n=JSON.parse(e.data);if(!n||typeof n!="object"){console.error("Invalid WebSocket message format");return}this.handleMessage(n)}catch(i){console.error("Failed to parse WebSocket message:",i)}},this.ws.onerror=e=>{console.error("WebSocket error:",e),this.emit("error",e)},this.ws.onclose=()=>{if(console.log("WebSocket disconnected"),this.isConnected=!1,this.emit("disconnected"),this.shouldReconnect&&this.reconnectAttempts<this.maxReconnectAttempts){this.reconnectAttempts++;const e=this.reconnectDelay*Math.pow(2,this.reconnectAttempts-1);console.log(`Reconnecting in ${e}ms (attempt ${this.reconnectAttempts}/${this.maxReconnectAttempts})`),setTimeout(()=>this.connect(),e)}}}catch(e){console.error("Failed to create WebSocket connection:",e),this.emit("error",e)}}handleMessage(t){const{type:s,payload:o,time:e}=t;this.emit(s,o,e),this.emit("message",{type:s,payload:o,time:e})}on(t,s){this.listeners.has(t)||this.listeners.set(t,[]);const o=this.listeners.get(t);o.includes(s)||o.push(s)}off(t,s){if(!this.listeners.has(t))return;const o=this.listeners.get(t),e=o.indexOf(s);e>-1&&o.splice(e,1)}emit(t,...s){this.listeners.has(t)&&this.listeners.get(t).forEach(o=>{try{o(...s)}catch(e){console.error("Error in WebSocket event handler:",e)}})}disconnect(){this.shouldReconnect=!1,this.ws&&(this.ws.close(),this.ws=null)}send(t){this.ws&&this.ws.readyState===WebSocket.OPEN?this.ws.send(JSON.stringify(t)):console.warn("WebSocket is not connected")}}window.wsClient=new WebSocketClient(typeof basePath!="undefined"?basePath:"");
